var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이 방송은 실제 상황입니다.","JPN":"お知らせします。","ENG":"This is not a drill.","TWN":"本次廣播的情況是全部屬實。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN_02"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"현재, 수도 상공에 다수의 미인가 함선이 출몰하였습니다.","JPN":"現在、首都の上空に多数の未認可艦船が出現しました。","ENG":"Currently, multiple unidentified ships have appeared in the capital's airspace.","TWN":"目前，首都上空出現多個未經許可的艦船。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"시민 여러분은 군 • 경의 지시에 따라 침착하게 지정된 대피소로 대피해 주시기 바라며…","JPN":"市民の皆さんは軍・警察の指示に従い、落ち着いて指定された避難所まで避難してください……","ENG":"Citizens are advised to evacuate in a composed manner to the assigned shelters in accordance with military and police directives.","TWN":"請各位市民按照軍警的指示，前往指定避難所……"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그래서…. 저 괴물이 수도에 오게 만들었단 말인가?","JPN":"それで……あの化け物を首都に来るように仕向けたと？","ENG":"So... You made that monster head toward the capital?","TWN":"所以說……你讓那怪物來到首都？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하하, 죄송하게 되었군요.","JPN":"はは、申し訳ありません。","ENG":"Haha. Sorry about that.","TWN":"哈哈，非常抱歉。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하지만 타나베린으로 향한 건 저희 쪽 예상 밖이었습니다.","JPN":"ですが、タナベリンに向かったのは予想外でした。","ENG":"But we didn't expect it to head to Tanaberin.","TWN":"但我們也沒料到她會選擇去達那貝林。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"저희도 신뢰 관계를 유지하기 위해 최선을 다했다는 사실은 알아 주세요.","JPN":"私たちも信頼関係を維持するために最善を尽くしたということだけはわかってください。","ENG":"Please note that we did our best to maintain our truce.","TWN":"希望您能明白，我們已經為彼此的信任關係盡了全力。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"국장님, 수상관저에서 들어온 급보입니다.","JPN":"局長、首相官邸からの急報です。","ENG":"Sir, it's an urgent report from the Prime Minister.","TWN":"局長，來自首長官邸的緊急消息。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"뭐지? 보고하도록.","JPN":"何だ？　報告しろ。","ENG":"What? Let's hear it.","TWN":"什麼？報告吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"마에스트로 네퀴티아가 정부에 보낸 제안이라고 합니다. 보십시오.","JPN":"マエストロ・ネキティアから政府に送った提案とのことです。ご覧ください。","ENG":"It is a proposition to our government from Maestra Nequitia. Here you go, sir.","TWN":"這是指揮家·莉奎蒂亞向政府提出的提議。請過目。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"정기적으로, 국민의 10%를 제공하라…?","JPN":"定期的に、国民の10％を提供しろだと……？","ENG":"She wants us to provide her with 10% of the population on a regular basis...?","TWN":"定期獻出10%的國民……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"연령대와 성별의 비율까지…… 이건 제안이 아니라 우리 정부에 대한 모욕이지 않나!","JPN":"年齢層と性別の比率まで……これは提案ではなく、我々政府に対する侮辱ではないか！","ENG":"She even wrote the age and gender ratio... This isn't a proposition, it's a mockery of our government!","TWN":"還要求特定年齡段和性別比例……這不是提議，這是對我們政府的侮辱！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"하, 하지만…….","JPN":"で、ですが……","ENG":"H-however...","TWN":"可…可是……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"예, 각하. 방금 제안 내용을 확인했습니다.","JPN":"はい、閣下。ただいま、提案の内容を確認しました。","ENG":"Yes, Prime Minster. I just now confirmed the proposition.","TWN":"是，總理。剛看到提議內容。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>좋아. 그렇다면 설명할 수고는 덜었군.</color>","JPN":"<color=#ffd34c>よろしい。なら、説明する必要はないな。</color>","ENG":"<color=#ffd34c>Good. That saves me the trouble of explaining it to you.</color>","TWN":"<color=#ffd34c>很好。那我就長話短說。</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>계엄령은 이미 내렸다네. 보안국이 바쁘게 움직여 줘야겠어.</color>","JPN":"<color=#ffd34c>すでに戒厳令を敷いている。保安局には急いで動いてもらおう。</color>","ENG":"<color=#ffd34c>I've already declared martial law. I expect the National Security to be swift.</color>","TWN":"<color=#ffd34c>現在已經發布戒嚴令，安全局要抓緊時間採取行動。</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"각하, 지금 저 제안을 받아들이셨다는 겁니까? 저에게 한마디 언질이라도 주셨어야죠!","JPN":"閣下、あの提案を受け入れたとおっしゃっているのですか？　私に意見を求めることもなく！","ENG":"Sir, have you already accepted this proposition? You should have told me in advance!","TWN":"總理，難道您已經接受了她的提議嗎？至少應該和我說一聲！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>생각해 보게. 고위 침식체가 지금 우리 머리 위에 있어.</color>","JPN":"<color=#ffd34c>考えてみろ。高位侵食体が今我々の頭上にいるのだ。</color>","ENG":"<color=#ffd34c>Think about it. A high-tier C.O. is right above us.</color>","TWN":"<color=#ffd34c>你好好想一想。高階侵蝕體就在我們頭頂正上方。</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>10%라면 오히려 합리적인 거래지.</color>","JPN":"<color=#ffd34c>10％ならむしろ合理的な取引だろう。</color>","ENG":"<color=#ffd34c>10%? Sounds pretty reasonable if you ask me.</color>","TWN":"<color=#ffd34c>10%是一個合理的交易。</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"나랏일은 돈놀이가 아닙니다. 아시지 않습니까.","JPN":"国事を金の貸し借り程度に考えてはなりません。ご存じではありませんか。","ENG":"Running a country is not a business. You know that, sir.","TWN":"國政可不是做生意，您不也很清楚這一點嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그렇다면 자네가 다른 방안을 제시해 보겠나?</color>","JPN":"<color=#ffd34c>なら、君から他の意見を提示してみるか？</color>","ENG":"<color=#ffd34c>Then are you willing to propose another way?</color>","TWN":"<color=#ffd34c>那你能給我一個更好的方案嗎？</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>군에 차출을 시작하라고 말해 두었네. 괜한 소요가 일어나지 않게 해.</color>","JPN":"<color=#ffd34c>軍には選抜を始めるように話しておいた。変な騒動が起きないようにしろ。</color>","ENG":"<color=#ffd34c>The military has already been deployed. Try not to cause any delays.</color>","TWN":"<color=#ffd34c>我已經命令軍隊馬上挑出人選，你要防止發生不必要的騷動。</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……신이시여.","JPN":"……神様。","ENG":"...Dear god.","TWN":"……神啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"대피소로 가는 트럭입니다! 어서 타세요!","JPN":"避難所行きのトラックです！　早く乗ってください！","ENG":"This truck's headed to the shelter! Citizens, get on!","TWN":"是開往避難所的卡車！快上車！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CITIZEN_EXTRA_NULL_NULL","text":{"KOREA":"정말입니까? 아까부터 전부 같은 방향으로 가는 것 같던데….","JPN":"本当ですか？　さっきから全部同じ方向に向かってるようですけど……","ENG":"Really? But they all seemed to be headed in the same direction...","TWN":"真的嗎？怎麼都開往同一個方向……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L40_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"지, 지금 정부 지시가 농담으로 들립니까? 어서요!","JPN":"せ、政府の指示が冗談だとでも？　いいから、早く乗ってください！","ENG":"D-do you think this is a joke?! Now, get on!","TWN":"你…你不服從政府指示嗎？快點上車！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CITIZEN_EXTRA_NULL_NULL","text":{"KOREA":"그 말을 어떻게 믿으란 거요?","JPN":"それをどうやって信じろってんだ？","ENG":"You want us to believe that?","TWN":"我要怎麼相信你？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CITIZEN_EXTRA_NULL_NULL","text":{"KOREA":"맞아! 침식체가 나타났다는데 아무런 경고도 없었잖아!","JPN":"そうだ！　侵食体が現れたっていうのに、何の警告もなかっただろう！","ENG":"Yeah! A C.O. appeared, but there were no warnings!","TWN":"對啊！明明有侵蝕體卻沒有發出警告！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"呵嗯……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"아우성, 고함, 그리고 흐느끼는 소리.","JPN":"わめき声、叫び、そしてすすり泣く声。","ENG":"The sounds of screaming, shouting, and sobbing.","TWN":"慘叫、悲鳴、哭泣的聲音。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"이제 한 발의 총성만 더해지면 훌륭한 광경이 펼쳐지겠군요.","JPN":"あとは銃声が一発加われば、見事な光景となるでしょう。","ENG":"All that is left is a single gunshot to complete this excellent scenery.","TWN":"再加上一聲槍響，就會展開極為美麗的場景。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>타나베린의, 그리고 그로니아의 전 병력에게 전파합니다.</color>","JPN":"<color=#ffd34c>タナベリンの、そしてグロニアの全兵力に伝えます。</color>","ENG":"<color=#ffd34c>To all the forces of Tanaberin and Gronia.</color>","TWN":"<color=#ffd34c>達那貝林，還有格羅尼亞的全體士兵。</color>"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SECURITY_CA_SERGEANT_IN_TRAILER_4"},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"이 목소리는……?","JPN":"この声は……？","ENG":"That voice...","TWN":"這聲音是……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 이름은, 크리스티나 브레히트입니다.</color>","JPN":"<color=#ffd34c>私の名前はクリスティーナ・ブレヒトです。</color>","ENG":"<color=#ffd34c>My name is Christina Brecht.</color>","TWN":"<color=#ffd34c>我叫克莉絲蒂娜·布萊希特。</color>"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SECURITY_CA_SERGEANT_IN_TRAILER_5"}]`);export{e as default};